{
  "shots": [
    {
      "shot_id": "SH10",
      "priority": "P0",
      "intent": "石川的远端电话把调查推进到彩花私物和浅蓝丝巾，同时捕捉美咲手停在化妆品盒上的可疑反应。",
      "duration_sec": 5,
      "shot_type": "双人中近景",
      "movement": "固定机位",
      "framing_focus": "首帧稳定双人中近景：健一整理遗物的客厅地板旁，田中健一位于画面左中部，右手持 KENICHI_SMARTPHONE_01 靠近右耳，脸转向画面右侧的佐藤美咲；佐藤美咲在画面右侧半起身停住，右手指尖停在 AYAKA_COSMETIC_BOX_01 盒盖上，AYAKA_LIGHT_BLUE_SILK_SCARF_01 半铺在二人之间地板上，人物衣着完整，保持日常社交距离，朴素克制呈现。",
      "action_intent": "本镜头只承载石川远端电话信息；健一保持听电话姿势，眼神从美咲的脸短促落到她停在化妆品盒上的手，美咲嘴唇保持静止，右手不离开盒盖，浅蓝丝巾保持可见不被拿起。",
      "emotion_intent": "健一的警觉和美咲瞬间僵住的防备同时出现，让彩花私物与丝巾变成新的压力点。",
      "scene_id": "EP06_LIVINGROOM_ISHIKAWA_CALL",
      "scene_name": "健一整理遗物的客厅",
      "dialogue": [
        {
          "speaker": "石川悠一",
          "text": "田中先生，照片确认过了，小樱没事。但有新发现。你那边有彩花的私物吗？丝巾什么的。",
          "purpose": "通过电话确认小樱安全，并把警方调查推进到彩花私物与浅蓝丝巾。",
          "source": "phone",
          "listener": "田中健一"
        }
      ],
      "narration": [],
      "subtitle": [
        "田中先生，照片确认过了，小樱没事。但有新发现。你那边有彩花的私物吗？丝巾什么的。"
      ],
      "positive_core": "首帧稳定在健一整理遗物的客厅地板旁：田中健一左中部持 KENICHI_SMARTPHONE_01 靠近右耳并看向右侧佐藤美咲，佐藤美咲右侧半起身，右手停在 AYAKA_COSMETIC_BOX_01 上，AYAKA_LIGHT_BLUE_SILK_SCARF_01 半铺在二人之间地板上。电话里传来石川悠一的声音，画面内健一和美咲都保持沉默，嘴唇静止；手机屏幕朝向健一一侧，屏幕内容不展示。低饱和夜色客厅光影，竖屏9:16，写实电影感，人物衣着完整，保持日常社交距离，朴素克制呈现。",
      "first_frame_contract": {
        "location": "健一整理遗物的客厅地板旁",
        "visual_center": "田中健一听电话的侧脸与 KENICHI_SMARTPHONE_01，视线指向佐藤美咲停在 AYAKA_COSMETIC_BOX_01 上的手",
        "visible_characters": [
          "田中健一",
          "佐藤美咲"
        ],
        "character_positions": {
          "田中健一": "画面左中部，坐在客厅地板旁，右手持 KENICHI_SMARTPHONE_01 靠近右耳，眼睛看向佐藤美咲",
          "佐藤美咲": "画面右侧，半起身停住，右手指尖停在 AYAKA_COSMETIC_BOX_01 盒盖上，嘴唇保持静止"
        },
        "key_props": [
          "KENICHI_SMARTPHONE_01",
          "AYAKA_COSMETIC_BOX_01",
          "AYAKA_LIGHT_BLUE_SILK_SCARF_01"
        ],
        "speaking_state": "石川悠一为电话远端唯一声音；田中健一和佐藤美咲画面内沉默，嘴唇保持静止",
        "camera_motion_allowed": "固定机位"
      },
      "dialogue_blocking": {
        "active_speaker": "石川悠一（电话远端）",
        "first_speaker": "石川悠一（电话远端）",
        "speaker_visual_priority": "listener_visible",
        "silent_visible_characters": [
          "田中健一",
          "佐藤美咲"
        ],
        "lip_sync_policy": "remote_voice_listener_silent"
      },
      "i2v_contract": {
        "shot_task": "dialogue",
        "risk_level": "medium",
        "risk_notes": "电话远端声音与画面内双人同框，需锁定石川悠一为唯一发声者；健一和美咲只做极小眼神与手部停顿，嘴唇保持静止。",
        "prop_library": {
          "KENICHI_SMARTPHONE_01": {
            "display_name": "健一手机",
            "count": "1部",
            "size": "约15厘米 × 7厘米 × 0.8厘米",
            "color": "黑色机身，深色保护壳",
            "material": "玻璃屏幕，金属边框，硅胶保护壳",
            "structure": "直板智能手机",
            "canonical_motion_policy": "通话时由健一手持，靠近耳侧或胸前；远端声音镜头中屏幕朝内，不展示额外屏幕内容。"
          },
          "AYAKA_COSMETIC_BOX_01": {
            "display_name": "彩花化妆品盒",
            "count": "1个",
            "size": "约14厘米 × 9厘米 × 5厘米",
            "color": "米白色外壳，银色边框",
            "material": "硬质塑料外壳，金属铰链，内部有镜面和细粉质化妆品格",
            "structure": "翻盖式小盒，盒盖可打开，内部镜面固定在盖内侧",
            "canonical_motion_policy": "默认闭合放置；需要展示时可由美咲递给健一或停在地板上，不做复杂开合。"
          },
          "AYAKA_LIGHT_BLUE_SILK_SCARF_01": {
            "display_name": "浅蓝丝巾",
            "count": "1条",
            "size": "约150厘米 × 35厘米",
            "color": "浅蓝色，低饱和冷调",
            "material": "丝质，表面有柔和反光",
            "structure": "长方形薄丝巾，边缘有细窄卷边",
            "canonical_motion_policy": "默认折叠或半铺在健一膝前；只允许由健一或美咲手部触碰、捏紧、放下或滑落。"
          }
        },
        "prop_contract": [
          {
            "prop_id": "KENICHI_SMARTPHONE_01",
            "position": "首帧由田中健一右手持握，靠近右耳，位于画面左中部",
            "first_frame_visible": true,
            "motion_policy": "保持通话姿势，仅允许随健一微小呼吸产生轻微位移；屏幕始终朝内，不展示内容",
            "controlled_by": "田中健一"
          },
          {
            "prop_id": "AYAKA_COSMETIC_BOX_01",
            "position": "首帧闭合放在佐藤美咲右手下方的客厅地板上，位于画面右下侧",
            "first_frame_visible": true,
            "motion_policy": "保持闭合，不开合；美咲右手指尖停在盒盖上，可有极轻微收紧",
            "controlled_by": "佐藤美咲"
          },
          {
            "prop_id": "AYAKA_LIGHT_BLUE_SILK_SCARF_01",
            "position": "首帧半铺在田中健一与佐藤美咲之间的地板上，靠近健一膝前",
            "first_frame_visible": true,
            "motion_policy": "本镜头保持静止可见，不被拿起、不改变形态",
            "controlled_by": "none"
          }
        ],
        "phone_contract": {
          "holder": "田中健一",
          "screen_orientation": "screen facing inward toward holder",
          "screen_content_visible": false
        }
      },
      "source_basis": "对应 TARGET_FACTS 16：美咲起身时石川来电；石川在电话中说照片确认过、小樱没事，并询问健一身边是否有彩花私物和丝巾；健一沉默听电话看向美咲，美咲手停在化妆品盒上。"
    }
  ],
  "qa_report": [
    {
      "check": "shots length and shot id",
      "result": "pass",
      "notes": "仅输出 SH10 一个镜头，duration_sec 为 5。"
    },
    {
      "check": "I2V rule self-check",
      "result": "pass",
      "notes": "本镜头为电话远端对白，唯一主动说话人为石川悠一；画面内田中健一和佐藤美咲保持沉默，嘴唇静止。"
    },
    {
      "check": "phone contract",
      "result": "pass",
      "notes": "KENICHI_SMARTPHONE_01 由田中健一持握，屏幕朝内，屏幕内容不可见，远端来电者不出现在画面中。"
    },
    {
      "check": "prop continuity",
      "result": "pass",
      "notes": "复用 KENICHI_SMARTPHONE_01、AYAKA_COSMETIC_BOX_01、AYAKA_LIGHT_BLUE_SILK_SCARF_01，并沿用道具目录中的数量、尺寸、颜色、材质、结构和运动策略。"
    },
    {
      "check": "first frame stability",
      "result": "pass",
      "notes": "framing_focus 与 positive_core 第一句均为单一客厅地点的稳定首帧，没有时间跳转或多地点动作链。"
    }
  ]
}
